import type { InputHTMLAttributes, KeyboardEvent, ReactNode } from 'react';
import type { TestComponentProps } from '../../types/test-component';
export type TextFieldSizeVariantsType = 'small' | 'medium' | 'large';
export type HelperPositionType = 'absolute' | 'block';
export interface TextFieldProps extends Omit<InputHTMLAttributes<HTMLInputElement>, 'size'>, TestComponentProps {
    /**
     * Заголовок поля.
     */
    label?: string;
    /**
     * Функция для управления событием keyDown
     */
    onKeyDown?(e: KeyboardEvent<HTMLInputElement>): void;
    /**
     * Идентификатор для текстового поля. Подставляется и в label.
     */
    inputId?: string;
    /**
     * Название класса для текстового поля.
     */
    inputClassName?: string;
    /**
     * Название класса для обертки компонента.
     */
    wrapperClassName?: string;
    /**
     * Размер, влияет на минимальную высоту и шрифт.
     */
    size?: TextFieldSizeVariantsType;
    /**
     * Признак, ошибка / нет ошибки.
     */
    error?: boolean;
    /**
     * Признак, блокировано / разблокировано.
     */
    disabled?: boolean;
    /**
     * Вспомогательный текст
     */
    helperText?: string;
    /**
     * Растягивает поле на всю ширину родителя.
     */
    fullWidth?: boolean;
    /**
     * Иконка в начале.
     */
    startAdornment?: ReactNode;
    /**
     * Иконка в конце.
     */
    endAdornment?: ReactNode;
    /**
     * Позиционирование helper text.
     */
    helperPosition?: HelperPositionType;
    /**
     * Указывает можеь ли проходить событие сквозь Adorments
     */
    isClickableAdornment?: boolean;
    /**
     * Счетчик скрытых options
     */
    counter?: React.JSX.Element;
    /**
     * Максимальное количество символов для ввода
     * При указании этого параметра поле будет блокировать ввод символов сверх лимита
     */
    maxLength?: number;
    /**
     * Отключает отображение счетчика символов.
     * Ограничение на ввод (maxLength) продолжает работать нативно.
     */
    disableMaxLength?: boolean;
    /**
     * Имитация стилей фокуса с помощью обычного класса
     */
    isFocused?: boolean;
    /**
     * Технический пропс для интеграции с составными компонентами (например, Select).
     * Не используйте его напрямую в продуктах — вместо этого управляйте счётчиком через API родительского компонента.
     */
    isShowCountOfValues?: boolean;
}
export interface StyledInput extends TextFieldProps {
    customSize: TextFieldSizeVariantsType;
}
